changeSet.sql:
drop materialized view if exists engine_cache_compact_no_duplicate; drop materialized view if exists engine_cache_compact;
create materialized view engine_cache_compact as ( select fen_key, "depth", raw_line from move_analysis where already_in_cache = false and raw_line is not null and depth is not null union select fen_key, "depth", raw_line from analysis_engine_data_cache where raw_line is not null);
create materialized view engine_cache_compact_no_duplicate as ( select fen_key, "depth", max(raw_line) as raw_line from engine_cache_compact group by fen_key, "depth");
create index if not exists engine_cache_compact_no_duplicate_fen_key_idx on engine_cache_compact_no_duplicate (fen_key); create index if not exists engine_cache_compact_no_duplicate_fen_key_depth_idx on engine_cache_compact_no_duplicate (fen_key, "depth");

update game
set contains_errors = true
where id = 'EYI11Ad81jKv';

update "user"
set puzzle_rating = 800
where puzzle_rating is null;

-- Fairy-Stockfish: always 11.2 UPDATE bot_game SET engine_version = '11.2' WHERE engine = 'FAIRYSTOCKFISH';
-- Pikafish before the 2024-04-28 upgrade UPDATE bot_game SET engine_version = '2022-12-26' WHERE engine = 'PIKAFISH' AND (created AT TIME ZONE 'UTC')::date < DATE '2024-04-28';
-- Pikafish after the 2024-04-28 upgrade UPDATE bot_game SET engine_version = '2023-03-05' WHERE engine = 'PIKAFISH' AND (created AT TIME ZONE 'UTC')::date > DATE '2024-04-28';
-- Pikafish games created on 2024-04-28 keep engine_version = NULL (unknown).
